import { forwardRef, useRef } from 'react';
import { useTooltip, type TooltipProp } from '../../hooks/useTooltip';

export interface ArvoIconButtonProps extends Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, 'type' | 'disabled'> {
  variant?: 'primary' | 'secondary' | 'tertiary' | 'outline' | 'danger';
  size?: 'xs' | 'sm' | 'md' | 'lg';
  type?: 'button' | 'submit' | 'reset';
  icon: string;
  tooltip: TooltipProp;
  isDisabled?: boolean;
  isSelected?: boolean;
  isLoading?: boolean;
}

const ArvoIconButton = forwardRef<HTMLButtonElement, ArvoIconButtonProps>(
  function ArvoIconButton(
    {
      variant = 'primary',
      size = 'md',
      type = 'button',
      icon,
      tooltip,
      isDisabled = false,
      isSelected,
      isLoading = false,
      className,
      onClick,
      onKeyDown,
      ...rest
    },
    ref
  ) {
    const internalRef = useRef<HTMLButtonElement | null>(null);
    const tooltipContent = typeof tooltip === 'string' ? tooltip : tooltip.content;

    useTooltip({ triggerRef: internalRef, tooltip });
    const classes = [
      'arvo-icon-btn',
      `arvo-btn--${variant}`,
      `arvo-btn--${size}`,
      isLoading ? 'loading' : '',
      isSelected === true ? 'active' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const blocked = isDisabled || isLoading;

    const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
      if (blocked) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onClick?.(e);
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLButtonElement>) => {
      if (blocked && (e.key === 'Enter' || e.key === ' ')) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onKeyDown?.(e);
    };

    const ariaPressedProp = isSelected !== undefined ? { 'aria-pressed': isSelected } : {};

    const mergeRefs = (node: HTMLButtonElement | null) => {
      internalRef.current = node;
      if (typeof ref === 'function') ref(node);
      else if (ref) ref.current = node;
    };

    return (
      <button
        ref={mergeRefs}
        type={type}
        disabled={isDisabled}
        {...rest}
        className={classes}
        aria-label={tooltipContent}
        aria-busy={isLoading ? true : undefined}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        {...ariaPressedProp}
      >
        <span
          className={`arvo-btn__ico o9con o9con-${icon}`}
          aria-hidden="true"
        />
      </button>
    );
  }
);

export default ArvoIconButton;
